provider "aws" {
  region = "us-east-1"
}

# Networking components for RDS instances
resource "aws_vpc" "main" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_support   = true
  enable_dns_hostnames = true
}

resource "aws_subnet" "subnet_a" {
  vpc_id            = aws_vpc.main.id
  cidr_block        = "10.0.1.0/24"
  availability_zone = "us-east-1a"
}

resource "aws_subnet" "subnet_b" {
  vpc_id            = aws_vpc.main.id
  cidr_block        = "10.0.2.0/24"
  availability_zone = "us-east-1b"
}

resource "aws_db_subnet_group" "main" {
  name       = "main"
  subnet_ids = [aws_subnet.subnet_a.id, aws_subnet.subnet_b.id]
}

# Internal RDS Instance (Private)
resource "aws_db_instance" "internal" {
  identifier           = "internal"
  allocated_storage    = 20
  engine               = "mysql"
  instance_class       = "db.t3.micro"
  db_name              = "internal"
  username             = "admin"
  password             = "SecurePassword123!"
  db_subnet_group_name = aws_db_subnet_group.main.name
  publicly_accessible  = false
  skip_final_snapshot  = true
}

# External RDS Instance (Public)
resource "aws_db_instance" "public" {
  identifier           = "public"
  allocated_storage    = 20
  engine               = "mysql"
  instance_class       = "db.t3.micro"
  db_name              = "public"
  username             = "admin"
  password             = "SecurePassword123!"
  db_subnet_group_name = aws_db_subnet_group.main.name
  publicly_accessible  = true
  skip_final_snapshot  = true
}

# Route 53 Public Hosted Zone
resource "aws_route53_zone" "public" {
  name = "database.example.com"
  comment = "Public zone for external users"
}

# Route 53 Private Hosted Zone (Split Horizon)
resource "aws_route53_zone" "private" {
  name = "database.example.com"
  comment = "Private zone for internal users"

  vpc {
    vpc_id = aws_vpc.main.id
  }
}

# DNS Record for External Users (Pointing to Public RDS)
resource "aws_route53_record" "external_db" {
  zone_id = aws_route53_zone.public.zone_id
  name    = "db.database.example.com"
  type    = "CNAME"
  ttl     = "300"
  records = [aws_db_instance.public.address]
}

# DNS Record for Internal Users (Pointing to Internal RDS)
resource "aws_route53_record" "internal_db" {
  zone_id = aws_route53_zone.private.zone_id
  name    = "db.database.example.com"
  type    = "CNAME"
  ttl     = "300"
  records = [aws_db_instance.internal.address]
}
