  provider            = aws.us_west
  name                = "us-west-env"
  application         = aws_elastic_beanstalk_application.app_us.name
  solution_stack_name = "64bit Amazon Linux 2023 v4.1.1 running Python 3.11"

  setting {
    namespace = "aws:autoscaling:launchconfiguration"
    name      = "IamInstanceProfile"
    value     = "aws-elasticbeanstalk-ec2-role"
  }
}

resource "aws_elastic_beanstalk_environment" "eu_central" {
  provider            = aws.eu_central
  name                = "eu-central-env"
  application         = aws_elastic_beanstalk_application.app_eu.name
  solution_stack_name = "64bit Amazon Linux 2023 v4.1.1 running Python 3.11"

  setting {
    namespace = "aws:autoscaling:launchconfiguration"
    name      = "IamInstanceProfile"
    value     = "aws-elasticbeanstalk-ec2-role"
  }
}

# Route53 Infrastructure
resource "aws_route53_zone" "main" {
  name = "myapp.example.com"
}

# Geolocation Routing for North America to US West
resource "aws_route53_record" "us_west" {
  zone_id = aws_route53_zone.main.zone_id
  name    = "web.myapp.example.com"
  type    = "CNAME"
  ttl     = 300

  geolocation_routing_policy {
    continent = "NA"
  }

  set_identifier = "us-west-endpoint"
  records        = [aws_elastic_beanstalk_environment.us_west.cname]
}

# Geolocation Routing for Europe to EU Central
resource "aws_route53_record" "eu_central" {
  zone_id = aws_route53_zone.main.zone_id
  name    = "web.myapp.example.com"
  type    = "CNAME"
  ttl     = 300

  geolocation_routing_policy {
    continent = "EU"
  }

  set_identifier = "eu-central-endpoint"
  records        = [aws_elastic_beanstalk_environment.eu_central.cname]
}

# Default Routing for other locations
resource "aws_route53_record" "default" {
  zone_id = aws_route53_zone.main.zone_id
  name    = "web.myapp.example.com"
  type    = "CNAME"
  ttl     = 300

  geolocation_routing_policy {
    country = "*"
  }

  set_identifier = "default-endpoint"
  records        = [aws_elastic_beanstalk_environment.us_west.cname]
}
