  description   = "Example CodeBuild project with no source and environment variables"
  build_timeout = "5"
  service_role  = aws_iam_role.example.arn

  artifacts {
    type = "NO_ARTIFACTS"
  }

  environment {
    compute_type                = "BUILD_GENERAL1_SMALL"
    image                       = "aws/codebuild/standard:5.0"
    type                        = "LINUX_CONTAINER"
    image_pull_credentials_type = "CODEBUILD"

    environment_variable {
      name  = "EXAMPLE_VAR"
      value = "example_value"
    }
  }

  source {
    type      = "NO_SOURCE"
    buildspec = "version: 0.2

phases:
  build:
    commands:
      - echo $EXAMPLE_VAR"
  }
}
