resource "aws_codebuild_project" "example" {
  name          = "example-codebuild-project"
  description   = "Example CodeBuild project with secondary artifacts"
  build_timeout = 5
  service_role  = aws_iam_role.example.arn

  artifacts {
    type = "NO_ARTIFACTS"
  }

  secondary_artifacts {
    artifact_identifier = "secondary_output"
    type                = "S3"
    location            = aws_s3_bucket.example.bucket
    path                = "/secondary/"
    packaging           = "ZIP"
    name                = "secondary-artifact.zip"
  }

  environment {
    compute_type                = "BUILD_GENERAL1_SMALL"
    image                       = "aws/codebuild/standard:5.0"
    type                        = "LINUX_CONTAINER"
    image_pull_credentials_type = "CODEBUILD"

    environment_variable {
      name  = "EXAMPLE_VAR"
      value = "example_value"
    }
  }

  source {
    type            = "GITHUB"
    location        = "https://github.com/aws-samples/aws-codebuild-samples.git"
    git_clone_depth = 1

    buildspec = <<-EOF
      version: 0.2
      phases:
        build:
          commands:
            - echo Building...
            - touch primary.txt
            - touch secondary.txt
      artifacts:
        files:
          - primary.txt
        secondary-artifacts:
          secondary_output:
            files:
              - secondary.txt
    EOF
  }

  source_version = "master"

  tags = {
    Environment = "Test"
  }
}

