resource "aws_codebuild_project" "example" {
  name          = "example-batch-project"
  description   = "Terraform managed CodeBuild project with batch configuration"
  build_timeout = 60
  service_role  = aws_iam_role.codebuild_example.arn

  artifacts {
    type = "NO_ARTIFACTS"
  }

  environment {
    compute_type                = "BUILD_GENERAL1_SMALL"
    image                       = "aws/codebuild/amazonlinux2-x86_64-standard:4.0"
    type                        = "LINUX_CONTAINER"
    image_pull_credentials_type = "CODEBUILD"

    environment_variable {
      name  = "ENVIRONMENT"
      value = "production"
    }
  }

  source {
    type            = "GITHUB"
    location        = "https://github.com/example/repo.git"
    git_clone_depth = 1

    buildspec = <<-EOF
      version: 0.2
      batch:
        fast-fail: false
        build-graph:
          - identifier: build1
            env:
              variables:
                BUILD_ID: "1"
          - identifier: build2
            depend-on: [build1]
            env:
              variables:
                BUILD_ID: "2"
      phases:
        build:
          commands:
            - echo Building ID $BUILD_ID
    EOF
  }

  build_batch_config {
    service_role    = aws_iam_role.codebuild_example.arn
    timeout_in_mins = 120

    restrictions {
      maximum_builds_allowed = 5
      compute_types_allowed  = ["BUILD_GENERAL1_SMALL", "BUILD_GENERAL1_MEDIUM"]
    }
  }

  logs_config {
    cloudwatch_logs {
      group_name  = "codebuild-log-group"
      stream_name = "codebuild-log-stream"
    }
  }

  tags = {
    Environment = "Test"
    ManagedBy   = "Terraform"
  }
}

