# IAM Role for Lex V2 Bot
resource "aws_iam_role" "lex_role" {
  name = "lex-pizza-bot-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "lexv2.amazonaws.com"
        }
      },
    ]
  })
}

# Lex V2 Bot Definition
resource "aws_lexv2models_bot" "pizza_bot" {
  name                        = "PizzaOrderingBot"
  role_arn                    = aws_iam_role.lex_role.arn
  data_privacy {
    child_directed = false
  }
  idle_session_ttl_in_seconds = 300
}

# Bot Locale (English US)
resource "aws_lexv2models_bot_locale" "en_us" {
  bot_id                          = aws_lexv2models_bot.pizza_bot.id
  bot_version                     = "DRAFT"
  locale_id                       = "en_US"
  nlu_intent_confidence_threshold = 0.40
}

# Main Intent: OrderPizza
resource "aws_lexv2models_intent" "order_pizza" {
  name        = "OrderPizza"
  bot_id      = aws_lexv2models_bot.pizza_bot.id
  bot_version = "DRAFT"
  locale_id   = aws_lexv2models_bot_locale.en_us.locale_id

  sample_utterance {
    utterance = "I want to order a pizza"
  }
  sample_utterance {
    utterance = "Can I get a pizza?"
  }
  sample_utterance {
    utterance = "Order a {PizzaType} pizza"
  }

  # Confirmation setting before fulfillment
  confirmation_setting {
    prompt_specification {
      max_retries = 2
      message_group {
        message {
          plain_text_message {
            value = "Okay, I have a {PizzaType} pizza ready for order. Should I proceed?"
          }
        }
      }
    }
    declination_response {
      message_group {
        message {
          plain_text_message {
            value = "No problem, the order has been cancelled."
          }
        }
      }
    }
  }

  # Follow-up question implemented as a Closing Response
  closing_response {
    message_group {
      message {
        plain_text_message {
          value = "Order placed! Would you like to add a side of cheesy bread or a drink to your order?"
        }
      }
    }
  }
}

# Slot for Pizza Type
resource "aws_lexv2models_slot" "pizza_type" {
  name        = "PizzaType"
  bot_id      = aws_lexv2models_bot.pizza_bot.id
  bot_version = "DRAFT"
  locale_id   = aws_lexv2models_bot_locale.en_us.locale_id
  intent_id   = aws_lexv2models_intent.order_pizza.intent_id

  slot_type_id = "AMAZON.FreeFormInput"

  value_elicitation_setting {
    slot_constraint = "Required"
    prompt_specification {
      max_retries = 3
      message_group {
        message {
          plain_text_message {
            value = "What kind of pizza would you like (e.g., Pepperoni, Margherita)?"
          }
        }
      }
    }
  }
}

# Bot Version (Required for deployment)
resource "aws_lexv2models_bot_version" "pizza_bot_v1" {
  bot_id      = aws_lexv2models_bot.pizza_bot.id
  locale_specification = {
    (aws_lexv2models_bot_locale.en_us.locale_id) = {
      source_bot_version = "DRAFT"
    }
  }

  depends_on = [
    aws_lexv2models_intent.order_pizza,
    aws_lexv2models_slot.pizza_type
  ]
}

