resource "aws_iam_role" "lex_bot_role" {
  name = "LexTripBookingRole"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "lex.amazonaws.com"
        }
      }
    ]
  })
}

resource "aws_lex_intent" "book_hotel" {
  name        = "BookHotel"
  description = "Intent to book a hotel room"

  fulfillment_activity {
    type = "ReturnIntent"
  }

  sample_utterances = [
    "I would like to book a hotel",
    "Book a hotel",
    "I want to make a hotel reservation"
  ]

  slot {
    name            = "Location"
    description     = "The city where the hotel is located"
    priority        = 1
    slot_constraint = "Required"
    slot_type       = "AMAZON.US_CITY"

    value_elicitation_prompt {
      max_attempts = 2
      message {
        content      = "Which city will you be staying in?"
        content_type = "PlainText"
      }
    }
  }

  slot {
    name            = "CheckInDate"
    description     = "The date of check-in"
    priority        = 2
    slot_constraint = "Required"
    slot_type       = "AMAZON.DATE"

    value_elicitation_prompt {
      max_attempts = 2
      message {
        content      = "What day do you want to check in?"
        content_type = "PlainText"
      }
    }
  }

  confirmation_prompt {
    max_attempts = 2
    message {
      content      = "Okay, I have you down for a stay in {Location} starting {CheckInDate}. Shall I book it?"
      content_type = "PlainText"
    }
  }

  rejection_statement {
    message {
      content      = "Okay, I have cancelled your reservation request."
      content_type = "PlainText"
    }
  }
}

resource "aws_lex_intent" "book_car" {
  name        = "BookCar"
  description = "Intent to book a rental car"

  fulfillment_activity {
    type = "ReturnIntent"
  }

  sample_utterances = [
    "Reserve a car",
    "Make a car reservation",
    "Book a car"
  ]

  slot {
    name            = "PickUpCity"
    priority        = 1
    slot_constraint = "Required"
    slot_type       = "AMAZON.US_CITY"

    value_elicitation_prompt {
      max_attempts = 2
      message {
        content      = "In what city do you need to rent a car?"
        content_type = "PlainText"
      }
    }
  }

  slot {
    name            = "CarType"
    priority        = 2
    slot_constraint = "Required"
    slot_type       = "AMAZON.AlphaNumeric" # Using a generic type for simplicity

    value_elicitation_prompt {
      max_attempts = 2
      message {
        content      = "What type of car would you like to rent? Our most popular options are economy, midsize, and luxury."
        content_type = "PlainText"
      }
    }
  }
}

resource "aws_lex_bot" "trip_booking_bot" {
  name                        = "TripBookingBot"
  child_directed              = false
  description                 = "Bot to assist with booking travel arrangements"
  locale                      = "en-US"
  idle_session_ttl_in_seconds = 300
  voice_id                    = "Salli"
  process_behavior            = "BUILD"

  abort_statement {
    message {
      content      = "I'm sorry, I'm not able to assist with that right now."
      content_type = "PlainText"
    }
  }

  clarification_prompt {
    max_attempts = 2
    message {
      content      = "I didn't understand that. What would you like to do?"
      content_type = "PlainText"
    }
  }

  intent {
    intent_name    = aws_lex_intent.book_hotel.name
    intent_version = "$LATEST"
  }

  intent {
    intent_name    = aws_lex_intent.book_car.name
    intent_version = "$LATEST"
  }
}
