  bot_id      = aws_lexv2models_bot.pizza_bot.id
  bot_version = aws_lexv2models_bot_locale.en_us.bot_version
  locale_id   = aws_lexv2models_bot_locale.en_us.locale_id
  name        = "OrderPizza"

  sample_utterance {
    utterance = "I want to order a pizza"
  }
  sample_utterance {
    utterance = "Can I have a yummy pizza please"
  }
  sample_utterance {
    utterance = "I'm hungry for pizza"
  }

  initial_response_setting {
    initial_response {
      message_group {
        message {
          plain_text_message {
            value = "Yay! Pizza time! I can help you pick the best pizza ever."
          }
        }
      }
    }
  }
}

