  description                 = "A fun pizza ordering bot designed for children"
  idle_session_ttl_in_seconds = 300
  role_arn                    = aws_iam_role.lex_role.arn

  data_privacy {
    child_directed = true # Required for COPPA compliance as requested
  }
}

resource "aws_lexv2models_bot_locale" "en_us" {
  bot_id                           = aws_lexv2models_bot.pizza_bot.id
  bot_version                      = "DRAFT"
  locale_id                        = "en_US"
  nlu_intent_confidence_threshold = 0.40
}

resource "aws_lexv2models_intent" "order_pizza" {
  bot_id      = aws_lexv2models_bot.pizza_bot.id
  bot_version = aws_lexv2models_bot_locale.en_us.bot_version
  locale_id   = aws_lexv2models_bot_locale.en_us.locale_id
  name        = "OrderPizza"

  sample_utterance {
    utterance = "I want to order a pizza"
  }
  sample_utterance {
    utterance = "Can I have a yummy pizza please"
  }
  sample_utterance {
    utterance = "I'm hungry for pizza"
  }

  initial_response_setting {
    initial_response {
      message_group {
        message {
          plain_text_message {
            value = "Yay! Pizza time! I can help you pick the best pizza ever."
          }
        }
      }
    }
  }
}

resource "aws_lexv2models_slot" "pizza_topping" {
  bot_id       = aws_lexv2models_bot.pizza_bot.id
  bot_version  = aws_lexv2models_bot_locale.en_us.bot_version
  locale_id    = aws_lexv2models_bot_locale.en_us.locale_id
  intent_id    = aws_lexv2models_intent.order_pizza.intent_id
  name         = "Topping"
  slot_type_id = "AMAZON.FreeFormInput"

  value_elicitation_setting {
    slot_constraint = "Required"
    prompt_specification {
      max_retries = 3
      message_group {
        message {
          plain_text_message {
            value = "What's your favorite topping? Cheese, Pepperoni, or maybe extra sprinkles?"
          }
        }
      }
    }
  }
}

resource "aws_lexv2models_bot_version" "v1" {
  bot_id      = aws_lexv2models_bot.pizza_bot.id
  locale_specification = {
    (aws_lexv2models_bot_locale.en_us.locale_id) = {
      source_bot_version = "DRAFT"
    }
  }

  depends_on = [aws_lexv2models_slot.pizza_topping]
}
