  filename      = "lambda_function_payload.zip" # Assumes a zip file exists or is handled by a build process
  function_name = "pizza_order_fulfillment"
  role          = aws_iam_role.lambda_role.arn
  handler       = "index.handler"
  runtime       = "python3.9"

  environment {
    variables = {
      BOT_NAME = "PizzaOrderingBot"
    }
  }
}

