resource "aws_kinesis_stream" "example" {
  name             = "example-input-stream"
  shard_count      = 1
  retention_period = 24
}

resource "aws_iam_role" "kinesis_analytics" {
  name = "example-kinesis-analytics-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "kinesisanalytics.amazonaws.com"
        }
      }
    ]
  })
}

resource "aws_iam_role_policy" "kinesis_analytics" {
  name = "example-kinesis-analytics-policy"
  role = aws_iam_role.kinesis_analytics.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = [
          "kinesis:GetShardIterator",
          "kinesis:GetRecords",
          "kinesis:DescribeStream"
        ]
        Effect   = "Allow"
        Resource = aws_kinesis_stream.example.arn
      }
    ]
  })
}

resource "aws_kinesis_analytics_application" "example" {
  name = "example-analytics-application"

  inputs {
    name_prefix = "SOURCE_SQL_STREAM"

    kinesis_stream {
      resource_arn = aws_kinesis_stream.example.arn
      role_arn     = aws_iam_role.kinesis_analytics.arn
    }

    parallelism {
      count = 1
    }

    schema {
      record_columns {
        mapping  = "$.sensor_id"
        name     = "SENSOR_ID"
        sql_type = "VARCHAR(64)"
      }
      record_columns {
        mapping  = "$.temperature"
        name     = "TEMPERATURE"
        sql_type = "DOUBLE"
      }

      record_format {
        mapping_parameters {
          json {
            record_row_path = "$"
          }
        }
      }
    }
  }

  code = <<EOT
CREATE OR REPLACE STREAM "DESTINATION_SQL_STREAM" (sensor_id VARCHAR(64), temperature DOUBLE);
CREATE OR REPLACE PUMP "STREAM_PUMP" AS INSERT INTO "DESTINATION_SQL_STREAM"
SELECT STREAM SENSOR_ID, TEMPERATURE FROM "SOURCE_SQL_STREAM_001";
EOT
}

