resource "aws_iam_role" "firehose_role" {
  name = "firehose_to_aoss_role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "firehose.amazonaws.com"
        }
      }
    ]
  })
}

resource "aws_iam_role_policy" "firehose_policy" {
  name = "firehose_aoss_policy"
  role = aws_iam_role.firehose_role.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "s3:AbortMultipartUpload",
          "s3:GetBucketLocation",
          "s3:GetObject",
          "s3:ListBucket",
          "s3:ListBucketMultipartUploads",
          "s3:PutObject"
        ]
        Resource = [
          aws_s3_bucket.firehose_backup.arn,
          "${aws_s3_bucket.firehose_backup.arn}/*"
        ]
      },
      {
        Effect = "Allow"
        Action = [
          "aoss:APIAccessAll"
        ]
        Resource = [aws_opensearchserverless_collection.example.arn]
      }
    ]
  })
}

# OpenSearch Serverless Encryption Policy
resource "aws_opensearchserverless_security_policy" "encryption" {
  name = "firehose-encryption-policy"
  type = "encryption"
  policy = jsonencode({
    Rules = [
      {
        ResourceType = "collection"
        Resource     = ["collection/firehose-collection"]
      }
    ]
    AWSOwnedKey = true
  })
}

# OpenSearch Serverless Network Policy (Public access for example)
resource "aws_opensearchserverless_security_policy" "network" {
  name = "firehose-network-policy"
  type = "network"
  policy = jsonencode([
    {
      Rules = [
        {
          ResourceType = "collection"
          Resource     = ["collection/firehose-collection"]
        },
        {
          ResourceType = "dashboard"
          Resource     = ["collection/firehose-collection"]
        }
      ]
      AllowFromPublic = true
    }
  ])
}

# OpenSearch Serverless Access Policy
resource "aws_opensearchserverless_access_policy" "access" {
  name = "firehose-access-policy"
  type = "data"
  policy = jsonencode([
    {
      Rules = [
        {
          ResourceType = "index"
          Resource     = ["index/firehose-collection/*"]
          Permission   = ["indices:CreateIndex", "indices:DescribeIndex", "indices:Write"]
        },
        {
          ResourceType = "collection"
          Resource     = ["collection/firehose-collection"]
          Permission   = ["aoss:CreateCollectionItems"]
        }
      ]
      Principal = [aws_iam_role.firehose_role.arn]
    }
  ])
}

# OpenSearch Serverless Collection
resource "aws_opensearchserverless_collection" "example" {
  name       = "firehose-collection"
  type       = "SEARCH"
  depends_on = [aws_opensearchserverless_security_policy.encryption]
}

# Kinesis Firehose Delivery Stream
resource "aws_kinesis_firehose_delivery_stream" "aoss_stream" {
  name        = "terraform-firehose-to-aoss"
  destination = "opensearchserverless"

  opensearchserverless_configuration {
    role_arn            = aws_iam_role.firehose_role.arn
    collection_endpoint = aws_opensearchserverless_collection.example.collection_endpoint
    index_name          = "logs"

    s3_configuration {
      role_arn           = aws_iam_role.firehose_role.arn
      bucket_arn         = aws_s3_bucket.firehose_backup.arn
      buffering_size     = 5
      buffering_interval = 300
      compression_format = "GZIP"

      cloudwatch_logging_options {
        enabled         = true
        log_group_name  = "/aws/kinesisfirehose/firehose-to-aoss"
        log_stream_name = "S3Backup"
      }
    }
  }
}

