resource "aws_kinesis_analytics_application" "test_application" {
  name = "terraform-kinesis-analytics-app"

  inputs {
    name_prefix = "SOURCE_SQL_STREAM"

    kinesis_stream {
      resource_arn = aws_kinesis_stream.test_stream.arn
      role_arn     = aws_iam_role.kinesis_analytics_role.arn
    }

    parallelism {
      count = 1
    }

    schema {
      record_columns {
        mapping  = "$.sensor_id"
        name     = "SENSOR_ID"
        sql_type = "INTEGER"
      }
      record_columns {
        mapping  = "$.temperature"
        name     = "TEMPERATURE"
        sql_type = "DOUBLE"
      }

      record_format {
        mapping_parameters {
          json {
            record_row_path = "$"
          }
        }
      }
    }
  }

  code = <<EOT
CREATE OR REPLACE STREAM "DESTINATION_SQL_STREAM" (sensor_id INTEGER, temperature DOUBLE);
CREATE OR REPLACE PUMP "STREAM_PUMP" AS INSERT INTO "DESTINATION_SQL_STREAM"
SELECT STREAM "SENSOR_ID", "TEMPERATURE"
FROM "SOURCE_SQL_STREAM_001"
WHERE "TEMPERATURE" > 25;
EOT
}

