resource "aws_route53_record" "eu_continent" {
  zone_id = aws_route53_zone.primary.zone_id
  name    = "app.example.com"
  type    = "A"
  ttl     = "300"

  set_identifier = "eu-continent-endpoint"

  geolocation_routing_policy {
    # 'EU' is the continent code for Europe
    continent = "EU"
  }

  records = ["2.2.2.2"]
}

resource "aws_route53_record" "default" {
  zone_id = aws_route53_zone.primary.zone_id
  name    = "app.example.com"
  type    = "A"
  ttl     = "300"

  set_identifier = "default-endpoint"

  geolocation_routing_policy {
    # Use '*' to define the default record for locations not explicitly covered
    continent = "*"
  }

  records = ["3.3.3.3"]
}
