# IAM Role for EKS Fargate Pod Execution
resource "aws_iam_role" "fargate_pod_execution" {
  name = "eks-fargate-pod-execution-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [{
      Action = "sts:AssumeRole"
      Effect = "Allow"
      Principal = {
        Service = "eks-fargate-pods.amazonaws.com"
      }
    }]
  })
}

# Attach the required policy for pod execution
resource "aws_iam_role_policy_attachment" "fargate_pod_execution_policy" {
  policy_arn = "arn:aws:iam::aws:policy/AmazonEKSFargatePodExecutionRolePolicy"
  role       = aws_iam_role.fargate_pod_execution.name
}

# Example VPC and Subnet setup with required tags for EKS association
resource "aws_vpc" "eks_vpc" {
  cidr_block = "10.0.0.0/16"
}

resource "aws_subnet" "fargate_subnet" {
  vpc_id            = aws_vpc.eks_vpc.id
  cidr_block        = "10.0.1.0/24"
  availability_zone = "us-east-1a"

  tags = {
    "kubernetes.io/cluster/${aws_eks_cluster.main.name}" = "shared"
  }
}

# EKS Cluster (Required context for Fargate Profile and patching)
resource "aws_eks_cluster" "main" {
  name     = "fargate-cluster"
  role_arn = aws_iam_role.eks_cluster_role.arn

  vpc_config {
    subnet_ids = [aws_subnet.fargate_subnet.id]
  }
}

resource "aws_iam_role" "eks_cluster_role" {
  name = "eks-cluster-role"
  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [{
      Action = "sts:AssumeRole"
      Effect = "Allow"
      Principal = { Service = "eks.amazonaws.com" }
    }]
  })
}

# EKS Fargate Profile for the kube-system namespace
resource "aws_eks_fargate_profile" "kube_system" {
  cluster_name           = aws_eks_cluster.main.name
  fargate_profile_name   = "kube-system-profile"
  pod_execution_role_arn = aws_iam_role.fargate_pod_execution.arn
  subnet_ids             = [aws_subnet.fargate_subnet.id]

  selector {
    namespace = "kube-system"
  }
}

# Data source to fetch authentication token for the cluster
data "aws_eks_cluster_auth" "main" {
  name = aws_eks_cluster.main.name
}

# Patching CoreDNS to run on Fargate using a null_resource
resource "null_resource" "patch_coredns" {
  depends_on = [aws_eks_fargate_profile.kube_system]

  provisioner "local-exec" {
    command = <<EOF
kubectl patch deployment coredns \n  -n kube-system \n  --type json \n  -p '[{"op": "remove", "path": "/spec/template/metadata/annotations/eks.amazonaws.com~1compute-type"}]' \n  --server=${aws_eks_cluster.main.endpoint} \n  --header="Authorization: Bearer ${data.aws_eks_cluster_auth.main.token}" \n  --insecure-skip-tls-verify
EOF
  }

  triggers = {
    endpoint = aws_eks_cluster.main.endpoint
    ca_data  = aws_eks_cluster.main.certificate_authority[0].data
    token    = data.aws_eks_cluster_auth.main.token
  }
}

