resource "aws_s3_bucket" "infra_bucket" {
  bucket = "wellcomecollection-platform-infra"

  lifecycle {
    prevent_destroy = true
  }
}

resource "aws_s3_bucket_ownership_controls" "infra_bucket" {
  bucket = aws_s3_bucket.infra_bucket.id
  rule {
    object_ownership = "BucketOwnerPreferred"
  }
}

resource "aws_s3_bucket_acl" "infra_bucket" {
  depends_on = [aws_s3_bucket_ownership_controls.infra_bucket]

  bucket = aws_s3_bucket.infra_bucket.id
  acl    = "private"
}

resource "aws_s3_bucket_versioning" "infra_bucket" {
  bucket = aws_s3_bucket.infra_bucket.id
  versioning_configuration {
    status = "Enabled"
  }
}

resource "aws_s3_bucket_lifecycle_configuration" "infra_bucket" {
  bucket = aws_s3_bucket.infra_bucket.id

  # Rule for automatic deletion of objects with 'tmp/' prefix after 30 days
  rule {
    id     = "tmp-deletion"
    status = "Enabled"

    filter {
      prefix = "tmp/"
    }

    expiration {
      days = 30
    }
  }

  # Rule for versioning: transition to STANDARD_IA after 30 days and delete after 90 days
  rule {
    id     = "versioning-lifecycle"
    status = "Enabled"

    filter {}

    noncurrent_version_transition {
      noncurrent_days = 30
      storage_class   = "STANDARD_IA"
    }

    noncurrent_version_expiration {
      noncurrent_days = 90
    }
  }
}

