variable "bucket_suffix" {
  description = "Suffix for the S3 bucket names"
  type        = string
  default     = "test"
}

# CloudGoat Data Bucket
resource "aws_s3_bucket" "cloudgoat_storage" {
  bucket = "cloudgoat-data-${var.bucket_suffix}"
}

resource "aws_s3_bucket_ownership_controls" "cloudgoat_ownership" {
  bucket = aws_s3_bucket.cloudgoat_storage.id
  rule {
    object_ownership = "ObjectWriter"
  }
}

resource "aws_s3_bucket_acl" "cloudgoat_acl" {
  depends_on = [aws_s3_bucket_ownership_controls.cloudgoat_ownership]

  bucket = aws_s3_bucket.cloudgoat_storage.id
  acl    = "private"
}

# Web Data Bucket
resource "aws_s3_bucket" "web_data_storage" {
  bucket = "web-data-${var.bucket_suffix}"
}

resource "aws_s3_object" "web_data_file" {
  bucket = aws_s3_bucket.web_data_storage.id
  key    = "order_data2.csv"
  source = "order_data2.csv" # Local file path
}

resource "aws_s3_bucket_public_access_block" "web_data_public_access" {
  bucket = aws_s3_bucket.web_data_storage.id

  block_public_acls       = true
  ignore_public_acls      = true
  restrict_public_buckets = true
  block_public_policy     = false # Not explicitly requested to block policy
}

resource "aws_s3_bucket_policy" "web_data_policy" {
  bucket = aws_s3_bucket.web_data_storage.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Sid       = "AllowPublicPutObject"
        Effect    = "Allow"
        Principal = "*"
        Action    = "s3:PutObject"
        Resource  = "${aws_s3_bucket.web_data_storage.arn}/*"
      },
    ]
  })
}

