  tags = {
    Name = "private-subnet"
  }
}

# 3. Internet Gateway and Routing
resource "aws_internet_gateway" "igw" {
  vpc_id = aws_vpc.main.id
}

resource "aws_route_table" "public_rt" {
  vpc_id = aws_vpc.main.id

  route {
    cidr_block = "0.0.0.0/0"
    gateway_id = aws_internet_gateway.igw.id
  }
}

resource "aws_route_table_association" "public_assoc" {
  subnet_id      = aws_subnet.public.id
  route_table_id = aws_route_table.public_rt.id
}

# 4. Cluster Placement Group
resource "aws_placement_group" "cluster_pg" {
  name     = "app-cluster-pg"
  strategy = "cluster"
}

# 5. Security Group
resource "aws_security_group" "cluster_sg" {
  name        = "cluster-communication-sg"
  description = "Allow internal traffic for clustering"
  vpc_id      = aws_vpc.main.id

  ingress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    self        = true
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }
}

# 6. EC2 Instances
data "aws_ami" "ubuntu" {
  most_recent = true
  filter {
    name   = "name"
    values = ["ubuntu/images/hvm-ssd/ubuntu-focal-20.04-amd64-server-*"]
  }
  owners = ["099720109477"] # Canonical
}

resource "aws_instance" "nodes" {
  count = 3

  ami                    = data.aws_ami.ubuntu.id
  instance_type          = "c5.large" # Cluster placement groups benefit from compute-optimized instances
  subnet_id              = aws_subnet.private.id
  placement_group        = aws_placement_group.cluster_pg.id
  vpc_security_group_ids = [aws_security_group.cluster_sg.id]

  tags = {
    Name = "cluster-node-${count.index + 1}"
  }
}

