extracted_code:
provider "aws" {
  region = "us-east-1"
}

# Data source to fetch the latest Amazon Linux 2 AMI
data "aws_ami" "amazon_linux_2" {
  most_recent = true
  owners      = ["amazon"]

  filter {
    name   = "name"
    values = ["amzn2-ami-hvm-*-x86_64-gp2"]
  }

  filter {
    name   = "virtualization-type"
    values = ["hvm"]
  }
}

resource "aws_vpc" "main" {
  cidr_block = "10.0.0.0/16"
}

# Subnet in us-east-1a
resource "aws_subnet" "subnet_a" {
  vpc_id            = aws_vpc.main.id
  cidr_block        = "10.0.1.0/24"
  availability_zone = "us-east-1a"
}

# Subnet in us-east-1b
resource "aws_subnet" "subnet_b" {
  vpc_id            = aws_vpc.main.id
  cidr_block        = "10.0.2.0/24"
  availability_zone = "us-east-1b"
}

# Instance in us-east-1a
resource "aws_instance" "server_a" {
  ami           = data.aws_ami.amazon_linux_2.id
  instance_type = "t2.micro"
  subnet_id     = aws_subnet.subnet_a.id

  tags = {
    Name = "Server-1a"
  }
}

# 50GB Volume for instance in us-east-1a
resource "aws_ebs_volume" "vol_a" {
  availability_zone = "us-east-1a"
  size              = 50

  tags = {
    Name = "Storage-1a"
  }
}

# Attach volume to instance in us-east-1a
resource "aws_volume_attachment" "attach_a" {
  device_name = "/dev/sdh"
  volume_id   = aws_ebs_volume.vol_a.id
  instance_id = aws_instance.server_a.id
}

# Instance in us-east-1b
resource "aws_instance" "server_b" {
  ami           = data.aws_ami.amazon_linux_2.id
  instance_type = "t2.micro"
  subnet_id     = aws_subnet.subnet_b.id

  tags = {
    Name = "Server-1b"
  }
}

# 50GB Volume for instance in us-east-1b
resource "aws_ebs_volume" "vol_b" {
  availability_zone = "us-east-1b"
  size              = 50

  tags = {
    Name = "Storage-1b"
  }
}

# Attach volume to instance in us-east-1b
resource "aws_volume_attachment" "attach_b" {
  device_name = "/dev/sdh"
  volume_id   = aws_ebs_volume.vol_b.id
  instance_id = aws_instance.server_b.id
}

