  vpc_id            = aws_vpc.msk_vpc.id
  cidr_block        = "10.0.3.0/24"
  availability_zone = "us-east-1c"
}

resource "aws_security_group" "msk_sg" {
  vpc_id = aws_vpc.msk_vpc.id
}

resource "aws_kms_key" "msk_kms" {
  description = "KMS key for MSK encryption at rest"
}

resource "aws_cloudwatch_log_group" "msk_cw_logs" {
  name = "msk-broker-logs"
}

resource "aws_s3_bucket" "msk_log_bucket" {
  bucket = "msk-broker-logs-bucket-${random_id.id.hex}"
}

resource "random_id" "id" {
  byte_length = 4
}

resource "aws_iam_role" "firehose_role" {
  name = "firehose_msk_role"

  assume_role_policy = <<EOF
{
  "Version": "2012-10-17",
  "Statement": [
    {
      "Action": "sts:AssumeRole",
      "Principal": {
        "Service": "firehose.amazonaws.com"
      },
      "Effect": "Allow",
      "Sid": ""
    }
  ]
}
EOF
}

resource "aws_kinesis_firehose_delivery_stream" "msk_firehose" {
  name        = "msk-delivery-stream"
  destination = "extended_s3"

  extended_s3_configuration {
    role_arn   = aws_iam_role.firehose_role.arn
    bucket_arn = aws_s3_bucket.msk_log_bucket.arn
  }
}

resource "aws_msk_cluster" "example" {
  cluster_name           = "example-msk-cluster"
  kafka_version          = "3.2.0"
  number_of_broker_nodes = 3

  broker_node_group_info {
    instance_type = "kafka.m5.large"
    client_subnets = [
      aws_subnet.subnet_az1.id,
      aws_subnet.subnet_az2.id,
      aws_subnet.subnet_az3.id,
    ]
    security_groups = [aws_security_group.msk_sg.id]
  }

  encryption_info {
    encryption_at_rest_kms_key_arn = aws_kms_key.msk_kms.arn
  }

  open_monitoring {
    prometheus {
      jmx_exporter {
        enabled_in_broker = true
      }
      node_exporter {
        enabled_in_broker = true
      }
    }
  }

  logging_info {
    broker_logs {
      cloudwatch_logs {
        enabled   = true
        log_group = aws_cloudwatch_log_group.msk_cw_logs.name
      }
      firehose {
        enabled         = true
        delivery_stream = aws_kinesis_firehose_delivery_stream.msk_firehose.name
      }
      s3 {
        enabled = true
        bucket  = aws_s3_bucket.msk_log_bucket.id
        prefix  = "logs/msk-"
      }
    }
  }
}

