provider "aws" {
  region = "us-east-1"
}

# --- Networking ---

resource "aws_vpc" "msk_vpc" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_hostnames = true
}

resource "aws_subnet" "subnet_a" {
  vpc_id            = aws_vpc.msk_vpc.id
  cidr_block        = "10.0.1.0/24"
  availability_zone = "us-east-1a"
}

resource "aws_subnet" "subnet_b" {
  vpc_id            = aws_vpc.msk_vpc.id
  cidr_block        = "10.0.2.0/24"
  availability_zone = "us-east-1b"
}

resource "aws_subnet" "subnet_c" {
  vpc_id            = aws_vpc.msk_vpc.id
  cidr_block        = "10.0.3.0/24"
  availability_zone = "us-east-1c"
}

resource "aws_security_group" "msk_sg" {
  name   = "msk-security-group"
  vpc_id = aws_vpc.msk_vpc.id

  ingress {
    from_port = 0
    to_port   = 0
    protocol  = "-1"
    self      = true
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }
}

# --- MSK Cluster ---

resource "aws_msk_cluster" "msk_cluster" {
  cluster_name           = "managed-msk-cluster"
  kafka_version          = "3.2.0"
  number_of_broker_nodes = 3

  broker_node_group_info {
    instance_type = "kafka.t3.small"
    client_subnets = [
      aws_subnet.subnet_a.id,
      aws_subnet.subnet_b.id,
      aws_subnet.subnet_c.id,
    ]
    security_groups = [aws_security_group.msk_sg.id]
  }

  encryption_info {
    encryption_in_transit {
      client_broker = "TLS"
    }
  }
}

# --- S3 Bucket for MSK Connect Plugin ---

resource "random_id" "bucket_id" {
  byte_length = 4
}

resource "aws_s3_bucket" "plugin_bucket" {
  bucket = "msk-plugins-${random_id.bucket_id.hex}"
}

resource "aws_s3_object" "plugin_zip" {
  bucket = aws_s3_bucket.plugin_bucket.id
  key    = "debezium.zip"
  source = "debezium.zip" # This assumes the file exists locally in the same directory
}

# --- MSK Connect Custom Plugin ---

resource "aws_mskconnect_custom_plugin" "debezium_plugin" {
  name         = "debezium-custom-plugin"
  content_type = "ZIP"
  location {
    s3 {
      bucket_arn = aws_s3_bucket.plugin_bucket.arn
      file_key   = aws_s3_object.plugin_zip.key
    }
  }
}

# --- IAM Role for MSK Connect ---

resource "aws_iam_role" "connector_role" {
  name = "msk-connect-connector-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "kafkaconnect.amazonaws.com"
        }
      }
    ]
  })
}

resource "aws_iam_role_policy" "connector_policy" {
  name = "msk-connect-policy"
  role = aws_iam_role.connector_role.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = [
          "kafka-cluster:Connect",
          "kafka-cluster:DescribeCluster",
          "kafka-cluster:AlterCluster",
          "kafka-cluster:WriteData",
          "kafka-cluster:ReadData",
          "kafka-cluster:DescribeTopic",
          "kafka-cluster:CreateTopic",
          "kafka-cluster:WriteDataIdempotently"
        ]
        Effect   = "Allow"
        Resource = "*"
      },
      {
        Action = [
          "s3:GetObject",
          "s3:ListBucket"
        ]
        Effect   = "Allow"
        Resource = [
          aws_s3_bucket.plugin_bucket.arn,
          "${aws_s3_bucket.plugin_bucket.arn}/*"
        ]
      }
    ]
  })
}

# --- MSK Connect Connector ---

resource "aws_mskconnect_connector" "debezium_connector" {
  name = "debezium-msk-connector"

  kafkaconnect_version = "2.7.1"

  capacity {
    autoscaling {
      mcu_count        = 1
      min_worker_count = 1
      max_worker_count = 2
    }
  }

  connector_configuration = {
    "connector.class"              = "io.debezium.connector.mysql.MySqlConnector"
    "tasks.max"                    = "1"
    "database.hostname"            = "example.rds.amazonaws.com"
    "database.port"                = "3306"
    "database.user"                = "admin"
    "database.password"            = "password"
    "database.server.id"           = "184054"
    "database.server.name"         = "dbserver1"
    "database.include.list"        = "inventory"
    "database.history.kafka.topic" = "dbhistory.inventory"
    "database.history.kafka.bootstrap.servers" = aws_msk_cluster.msk_cluster.bootstrap_brokers_tls
  }

  kafka_cluster {
    apache_kafka_cluster {
      bootstrap_servers = aws_msk_cluster.msk_cluster.bootstrap_brokers_tls
      vpc {
        security_groups = [aws_security_group.msk_sg.id]
        subnets         = [aws_subnet.subnet_a.id, aws_subnet.subnet_b.id, aws_subnet.subnet_c.id]
      }
    }
  }

  custom_plugin {
    arn      = aws_mskconnect_custom_plugin.debezium_plugin.arn
    revision = aws_mskconnect_custom_plugin.debezium_plugin.latest_revision
  }

  service_execution_role_arn = aws_iam_role.connector_role.arn

  depends_on = [aws_iam_role_policy.connector_policy]
}

