    "database.user"                  = "user"
    "database.password"              = "password"
    "database.dbname"                = "example"
    "database.server.name"           = "example"
  }

  kafka_cluster {
    apache_kafka_cluster {
      bootstrap_servers = aws_msk_cluster.example.bootstrap_brokers_tls
      vpc {
        security_groups = [aws_security_group.msk_sg.id]
        subnets         = [aws_subnet.subnet_az1.id, aws_subnet.subnet_az2.id, aws_subnet.subnet_az3.id]
      }
    }
  }

  custom_plugin {
    arn      = aws_mskconnect_custom_plugin.debezium.arn
    revision = aws_mskconnect_custom_plugin.debezium.latest_revision
  }

  service_execution_role_arn = aws_iam_role.connector_role.arn
}
```

