resource "aws_neptune_cluster_parameter_group" "example" {
  family      = "neptune1.2"
  name        = "example-cluster-params"
  description = "Custom Neptune cluster parameter group"

  parameter {
    name  = "neptune_enable_audit_log"
    value = "1"
  }
}

resource "aws_security_group" "neptune_sg" {
  name        = "neptune-sg"
  description = "Allow Neptune access only from specific subnets"
  vpc_id      = aws_vpc.main.id

  ingress {
    from_port   = 8182
    to_port     = 8182
    protocol    = "tcp"
    cidr_blocks = [aws_subnet.subnet_a.cidr_block, aws_subnet.subnet_b.cidr_block]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }
}

