resource "aws_security_group" "neptune_sg" {
  name        = "allow_example_subnet"
  description = "Allow inbound traffic from example subnet"
  vpc_id      = aws_vpc.main.id

  ingress {
    description = "Neptune access from example subnet"
    from_port   = 8182
    to_port     = 8182
    protocol    = "tcp"
    cidr_blocks = [aws_subnet.example_a.cidr_block]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }
}

