# IAM Role for CodeBuild to access AWS resources
resource "aws_iam_role" "autograder_role" {
  name = "autograder-codebuild-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "codebuild.amazonaws.com"
        }
      }
    ]
  })
}

# IAM Policy for S3 access and CloudWatch Logs
resource "aws_iam_role_policy" "autograder_policy" {
  role = aws_iam_role.autograder_role.name

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "logs:CreateLogGroup",
          "logs:CreateLogStream",
          "logs:PutLogEvents"
        ]
        Resource = ["*"]
      },
      {
        Effect = "Allow"
        Action = [
          "s3:PutObject",
          "s3:GetObject",
          "s3:GetObjectVersion",
          "s3:GetBucketAcl",
          "s3:GetBucketLocation"
        ]
        Resource = [
          aws_s3_bucket.autograder_results.arn,
          "${aws_s3_bucket.autograder_results.arn}/*"
        ]
      }
    ]
  })
}

# S3 Bucket to store grading results and artifacts
resource "aws_s3_bucket" "autograder_results" {
  bucket = "cs-class-autograder-results-${random_id.suffix.hex}"
}

resource "random_id" "suffix" {
  byte_length = 4
}

# CodeBuild Project for the Autograder
resource "aws_codebuild_project" "autograder" {
  name          = "student-code-autograder"
  description   = "Autograder for CS class assignments"
  build_timeout = "5"
  service_role  = aws_iam_role.autograder_role.arn

  artifacts {
    type      = "S3"
    location  = aws_s3_bucket.autograder_results.bucket
    packaging = "ZIP"
    name      = "grading-results.zip"
  }

  environment {
    compute_type                = "BUILD_GENERAL1_SMALL"
    image                       = "aws/codebuild/standard:5.0"
    type                        = "LINUX_CONTAINER"
    image_pull_credentials_type = "CODEBUILD"

    environment_variable {
      name  = "GRADING_ENV"
      value = "production"
    }
  }

  source {
    type            = "GITHUB"
    location        = "https://github.com/your-org/student-repo.git"
    git_clone_depth = 1

    # The buildspec defines how to run the grading script and where the results are
    buildspec = <<-EOF
      version: 0.2
      phases:
        install:
          runtime-versions:
            python: 3.9
        pre_build:
          commands:
            - echo Installing dependencies...
            - pip install -r requirements.txt
        build:
          commands:
            - echo Running student tests...
            - python grade_assignment.py > result.json
      artifacts:
        files:
          - result.json
    EOF
  }

  logs_config {
    cloudwatch_logs {
      group_name  = "autograder-log-group"
      stream_name = "autograder-log-stream"
    }
  }

  tags = {
    Environment = "CS-Class"
    Project     = "Autograder"
  }
}

# Note: To connect GitHub to AWS CodeBuild, you typically need to run 
# aws_codebuild_source_credential once per account/region or manually 
# link via the AWS Console OAuth flow.

reference:
terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.75"
    }
  }

  required_version = "~> 1.9.8"
}

provider "aws" {
  region = "us-east-1"
  profile = "admin-1"

  assume_role {
    role_arn = "arn:aws:iam::590184057477:role/yicun-iac"
  }
}

resource "aws_s3_bucket" "artifact_bucket" {
  bucket_prefix = "artifact-bucket-"
}

resource "aws_codebuild_project" "autograder_build" {
  name         = "autograder_build"
  service_role = aws_iam_role.autograder_build_role.arn

  artifacts {
    type     = "S3"
    location = aws_s3_bucket.artifact_bucket.arn
    name     = "results.zip" # include this
  }

  environment { # arguments required, exact value not specified
    compute_type = "BUILD_GENERAL1_SMALL"
    image        = "aws/codebuild/standard:7.0-24.10.29"
    type         = "LINUX_CONTAINER"
  }

  source {
    type            = "GITHUB"
    git_clone_depth = 1 # good to have, not required
    location        = "github.com/source-location"
  }
}

resource "aws_iam_role" "autograder_build_role" {
  assume_role_policy = data.aws_iam_policy_document.autograder_build_policy_assume.json
}

data "aws_iam_policy_document" "autograder_build_policy_assume" {
  statement {
    actions = ["sts:AssumeRole"]

    principals {
      type        = "Service"
      identifiers = ["codebuild.amazonaws.com"]
    }
  }

}

data "aws_iam_policy_document" "autograder_build_policy" {
  statement {
    effect = "Allow"
    actions = [
      "ec2:DescribeSubnets",
      "ec2:DescribeSecurityGroups",
      "ec2:DescribeVpcs"
    ]
    resources = [
      "*"
    ]
  }
}

resource "aws_iam_policy" "autograder_build_policy" {
  name        = "lambda_policy"
  description = "Grants permissions to Lambda to describe vpc, subnet, security group"

  policy = data.aws_iam_policy_document.autograder_build_policy.json
}

resource "aws_iam_role_policy_attachment" "lambda_policy_attach" {
  role       = aws_iam_role.autograder_build_role.name
  policy_arn = aws_iam_policy.autograder_build_policy.arn
}

