# S3 Bucket to store grading results and logs
resource "aws_s3_bucket" "autograder_results" {
  bucket        = "cs-autograder-results-${random_id.suffix.hex}"
  force_destroy = true
}

resource "aws_s3_bucket_public_access_block" "autograder_results_access" {
  bucket                  = aws_s3_bucket.autograder_results.id
  block_public_acls       = true
  block_public_policy     = true
  ignore_public_acls      = true
  restrict_public_buckets = true
}

# IAM Role for CodeBuild to access S3 and CloudWatch
resource "aws_iam_role" "codebuild_service_role" {
  name = "autograder-codebuild-role-${random_id.suffix.hex}"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "codebuild.amazonaws.com"
        }
      }
    ]
  })
}

resource "aws_iam_role_policy" "codebuild_policy" {
  name = "autograder-policy"
  role = aws_iam_role.codebuild_service_role.name

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "logs:CreateLogGroup",
          "logs:CreateLogStream",
          "logs:PutLogEvents"
        ]
        Resource = ["*"]
      },
      {
        Effect = "Allow"
        Action = [
          "s3:PutObject",
          "s3:GetObject",
          "s3:GetBucketLocation"
        ]
        Resource = [
          aws_s3_bucket.autograder_results.arn,
          "${aws_s3_bucket.autograder_results.arn}/*"
        ]
      }
    ]
  })
}

# CodeBuild Project for the Autograder
resource "aws_codebuild_project" "autograder" {
  name          = "cs-autograder-project"
  description   = "Autograder for CS class student submissions"
  build_timeout = "5"
  service_role  = aws_iam_role.codebuild_service_role.arn

  artifacts {
    type     = "S3"
    location = aws_s3_bucket.autograder_results.bucket
    name     = "grading-output"
  }

  environment {
    compute_type                = "BUILD_GENERAL1_SMALL"
    image                       = "aws/codebuild/standard:5.0"
    type                        = "LINUX_CONTAINER"
    image_pull_credentials_type = "CODEBUILD"

    environment_variable {
      name  = "GRADING_ENV"
      value = "production"
    }
  }

  source {
    type            = "GITHUB"
    location        = "https://github.com/your-org/student-repo-template.git"
    git_clone_depth = 1

    # Basic buildspec to run tests and output results
    buildspec = <<-EOF
      version: 0.2
      phases:
        install:
          runtime-versions:
            python: 3.9
          commands:
            - pip install pytest
        build:
          commands:
            - echo "Running student tests..."
            - pytest --junitxml=results.xml || true
      artifacts:
        files:
          - results.xml
    EOF
  }

  source_version = "main"

  tags = {
    Environment = "Education"
  }
}

# Webhook to trigger build on GitHub Push (requires GitHub token to be configured in AWS)
