    filter {
      type    = "EVENT"
      pattern = "PUSH"
    }
  }
}

# CloudWatch Log Group for CodeBuild logs
resource "aws_cloudwatch_log_group" "autograder_logs" {
  name              = "/aws/codebuild/${aws_codebuild_project.autograder.name}"
  retention_in_days = 7
}

