resource "aws_codebuild_project" "autograder" {
  name          = "cs-class-autograder"
  description   = "Runs student code from GitHub and stores results in S3"
  build_timeout = "10"
  service_role  = aws_iam_role.codebuild_role.arn

  artifacts {
    type      = "S3"
    location  = aws_s3_bucket.autograder_results.name
    packaging = "ZIP"
    name      = "grading-output"
