version: 0.2
phases:
  install:
    commands:
      - echo "Installing test dependencies..."
  pre_build:
    commands:
      - echo "Validating submission format..."
  build:
    commands:
      - echo "Running Autograder..."
      - make test > results.log
  post_build:
    commands:
      - echo "Grading completed on `date`"
artifacts:
  files:
    - results.log
    - "**/test-reports/*"
EOF
  }

  logs_config {
    cloudwatch_logs {
      group_name  = "autograder-logs"
      stream_name = "submission-eval"
    }
  }
}

