        Action   = ["s3:PutObject", "s3:GetObject", "s3:ListBucket"]
        Effect   = "Allow"
        Resource = ["${aws_s3_bucket.cat_storage.arn}", "${aws_s3_bucket.cat_storage.arn}/*"]
      },
      {
        Action   = ["logs:CreateLogGroup", "logs:CreateLogStream", "logs:PutLogEvents"]
        Effect   = "Allow"
        Resource = "arn:aws:logs:*:*:*"
      }
    ]
  })
}

resource "aws_iam_role_policy_attachment" "lambda_attach" {
  role       = aws_iam_role.lambda_role.name
  policy_arn = aws_iam_policy.lambda_policy.arn
}

# Lambda function logic
data "archive_file" "lambda_zip" {
  type        = "zip"
  output_path = "${path.module}/lambda.zip"
  source {
    content  = <<EOF
import json
import boto3
import base64
import os
import random

s3 = boto3.client('s3')
BUCKET = os.environ['BUCKET_NAME']

def handler(event, context):
    path = event.get('path')
    http_method = event.get('httpMethod')

    if path == '/upload' and http_method == 'POST':
        try:
            file_content = base64.b64decode(event['body'])
            file_name = f"cat_{context.aws_request_id}.jpg"
            s3.put_object(Bucket=BUCKET, Key=file_name, Body=file_content, ContentType='image/jpeg')
            return {
                'statusCode': 200,
                'body': json.dumps({'message': f'Cat uploaded as {file_name}'})
            }
        except Exception as e:
            return {'statusCode': 500, 'body': str(e)}

    elif path == '/random' and http_method == 'GET':
        try:
            objects = s3.list_objects_v2(Bucket=BUCKET).get('Contents', [])
            if not objects:
                return {'statusCode': 404, 'body': 'No cat pictures found!'}

            random_cat = random.choice(objects)['Key']
            url = s3.generate_presigned_url('get_object', 
                Params={'Bucket': BUCKET, 'Key': random_cat}, 
                ExpiresIn=3600)

            return {
                'statusCode': 302,
                'headers': {'Location': url}
            }
        except Exception as e:
            return {'statusCode': 500, 'body': str(e)}

    return {'statusCode': 404, 'body': 'Not Found'}
EOF
    filename = "index.py"
  }
}

resource "aws_lambda_function" "cat_handler" {
  filename         = data.archive_file.lambda_zip.output_path
  function_name    = "cat-service-function"
  role             = aws_iam_role.lambda_role.arn
  handler          = "index.handler"
  runtime          = "python3.9"
  source_code_hash = data.archive_file.lambda_zip.output_base64sha256

  environment {
    variables = {
      BUCKET_NAME = aws_s3_bucket.cat_storage.id
    }
  }
}

