extracted_code:
provider "aws" {
  region = "us-east-1"
}

# IAM Role for AWS Backup to assume
resource "aws_iam_role" "backup_role" {
  name = "aws-backup-service-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "backup.amazonaws.com"
        }
      }
    ]
  })
}

# Attach the required policy to the IAM role for AWS Backup
resource "aws_iam_role_policy_attachment" "backup_policy" {
  policy_arn = "arn:aws:iam::aws:policy/service-role/AWSBackupServiceRolePolicyForBackup"
  role       = aws_iam_role.backup_role.name
}

# EC2 Instance to be backed up
resource "aws_instance" "example_ec2" {
  ami           = "ami-0c55b159cbfafe1f0" # Amazon Linux 2 (Example AMI)
  instance_type = "t3.micro"

  tags = {
    Name = "BackupEnabledServer"
  }
}

# AWS Backup Vault to store snapshots
resource "aws_backup_vault" "example_vault" {
  name = "ec2-backup-vault"
}

# AWS Backup Plan defining the schedule
resource "aws_backup_plan" "example_plan" {
  name = "daily-midnight-backup-plan"

  rule {
    rule_name         = "daily-at-midnight"
    target_vault_name = aws_backup_vault.example_vault.name
    schedule          = "cron(0 0 * * ? *)" # Midnight UTC daily

    lifecycle {
      delete_after = 30 # Retain backups for 30 days
    }
  }
}

# Selection to link the EC2 instance to the Backup Plan
resource "aws_backup_selection" "example_selection" {
  iam_role_arn = aws_iam_role.backup_role.arn
  name         = "ec2-instance-selection"
  plan_id      = aws_backup_plan.example_plan.id

  resources = [
    aws_instance.example_ec2.arn
  ]
}

