provider "aws" {
  region = "us-east-1"
}

# Create a private key for the EC2 Instance
resource "tls_private_key" "example" {
  algorithm = "RSA"
  rsa_bits  = 4096
}

# Create an AWS Key Pair
resource "aws_key_pair" "generated_key" {
  key_name   = "backup-instance-key"
  public_key = tls_private_key.example.public_key_openssh
}

# Fetch the latest Amazon Linux 2 AMI
data "aws_ami" "amazon_linux_2" {
  most_recent = true
  owners      = ["amazon"]

  filter {
    name   = "name"
    values = ["amzn2-ami-hvm-*-x86_64-gp2"]
  }
}

# Create the EC2 Instance
resource "aws_instance" "example" {
  ami           = data.aws_ami.amazon_linux_2.id
  instance_type = "t3.micro"
  key_name      = aws_key_pair.generated_key.key_name

  tags = {
    Name = "BackupEnabledInstance"
  }
}

# Create an AWS Backup Vault
resource "aws_backup_vault" "example" {
  name = "ec2_backup_vault"
}

# Create an AWS Backup Plan (Daily at Midnight)
resource "aws_backup_plan" "example" {
  name = "daily_midnight_backup_plan"

  rule {
    rule_name         = "at_midnight_rule"
    target_vault_name = aws_backup_vault.example.name
    schedule          = "cron(0 0 * * ? *)"

    lifecycle {
      delete_after = 30 # Retain backups for 30 days
    }
  }
}

