resource "random_id" "bucket_suffix" {
  byte_length = 4
}

# S3 Bucket for Video Content
resource "aws_s3_bucket" "video_content" {
  bucket = "video-streaming-content-${random_id.bucket_suffix.hex}"
}

resource "aws_s3_bucket_public_access_block" "video_content" {
  bucket = aws_s3_bucket.video_content.id

  block_public_acls       = true
  block_public_policy     = true
  ignore_public_acls      = true
  restrict_public_buckets = true
}

# CloudFront Origin Access Control (OAC)
resource "aws_cloudfront_origin_access_control" "oac" {
  name                              = "s3-video-oac"
  description                       = "Origin Access Control for video S3 bucket"
  origin_access_control_origin_type = "s3"
  signing_behavior                  = "always"
  signing_protocol                  = "sigv4"
}

# Route 53 Public Hosted Zone
resource "aws_route53_zone" "streaming_zone" {
  name = "example-video-stream.com"
}

# SSL Certificate for custom domain (Required for CloudFront HTTPS with Route53)
resource "aws_acm_certificate" "cert" {
  domain_name       = "video.example-video-stream.com"
  validation_method = "DNS"

  lifecycle {
    create_before_destroy = true
  }
}

# DNS Record for ACM validation
resource "aws_route53_record" "cert_validation" {
  for_each = {
    for dvo in aws_acm_certificate.cert.domain_validation_options : dvo.domain_name => {
      name   = dvo.resource_record_name
      record = dvo.resource_record_value
      type   = dvo.resource_record_type
    }
  }

  allow_overwrite = true
  name            = each.value.name
  records         = [each.value.record]
  ttl             = 60
  type            = each.value.type
  zone_id         = aws_route53_zone.streaming_zone.zone_id
}

# CloudFront Distribution
resource "aws_cloudfront_distribution" "video_dist" {
  origin {
    domain_name              = aws_s3_bucket.video_content.bucket_regional_domain_name
    origin_access_control_id = aws_cloudfront_origin_access_control.oac.id
    origin_id                = "S3VideoOrigin"
  }

  enabled             = true
  is_ipv6_enabled     = true
  comment             = "Global video delivery distribution"
  default_root_object = "index.html"

  aliases = ["video.example-video-stream.com"]

  default_cache_behavior {
    allowed_methods  = ["GET", "HEAD", "OPTIONS"]
    cached_methods   = ["GET", "HEAD"]
    target_origin_id = "S3VideoOrigin"

    forwarded_values {
      query_string = false
      cookies {
        forward = "none"
      }
    }

    viewer_protocol_policy = "redirect-to-https"
    min_ttl                = 0
    default_ttl            = 3600
    max_ttl                = 86400
  }

  price_class = "PriceClass_All" # Distribute globally

  restrictions {
    geo_restriction {
      restriction_type = "none"
    }
  }

  viewer_certificate {
    acm_certificate_arn      = aws_acm_certificate.cert.arn
    ssl_support_method       = "sni-only"
    minimum_protocol_version = "TLSv1.2_2021"
  }
}

# S3 Bucket Policy to allow CloudFront OAC access
resource "aws_s3_bucket_policy" "allow_cloudfront_oac" {
  bucket = aws_s3_bucket.video_content.id
  policy = data.aws_iam_policy_document.cloudfront_oac_access.json
}

data "aws_iam_policy_document" "cloudfront_oac_access" {
  statement {
    actions   = ["s3:GetObject"]
    resources = ["${aws_s3_bucket.video_content.arn}/*"]

    principals {
      type        = "Service"
      identifiers = ["cloudfront.amazonaws.com"]
    }

    condition {
      test     = "StringEquals"
      variable = "AWS:SourceArn"
      values   = [aws_cloudfront_distribution.video_dist.arn]
    }
  }
}

# Route 53 Alias Record pointing to CloudFront
resource "aws_route53_record" "video_dns" {
  zone_id = aws_route53_zone.streaming_zone.zone_id
  name    = "video.example-video-stream.com"
  type    = "A"

  alias {
    name                   = aws_cloudfront_distribution.video_dist.domain_name
    zone_id                = aws_cloudfront_distribution.video_dist.hosted_zone_id
    evaluate_target_health = false
  }
}
