```hcl
provider "aws" {
  region = "us-east-1"
}

# 1. AWS VPC Module to handle network infrastructure
module "vpc" {
  source  = "terraform-aws-modules/vpc/aws"
  version = "5.0.0"

  name = "streaming-site-vpc"
  cidr = "10.0.0.0/16"

  azs             = ["us-east-1a", "us-east-1b"]
  private_subnets = ["10.0.1.0/24", "10.0.2.0/24"]
  public_subnets  = ["10.0.101.0/24", "10.0.102.0/24"]

  enable_nat_gateway = true
  single_nat_gateway = true

  tags = {
    Environment = "production"
    Application = "video-streaming"
  }
}

# 2. Security Group for the Application Load Balancer
resource "aws_security_group" "alb_sg" {
  name        = "streaming-alb-sg"
  description = "Allow HTTP traffic to load balancer"
  vpc_id      = module.vpc.vpc_id

  ingress {
    from_port   = 80
    to_port     = 80
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }
}

# 3. Security Group for the EC2 Instances
resource "aws_security_group" "ec2_sg" {
  name        = "streaming-ec2-sg"
  description = "Allow traffic from ALB only"
  vpc_id      = module.vpc.vpc_id

  ingress {
    from_port       = 80
    to_port         = 80
    protocol        = "tcp"
    security_groups = [aws_security_group.alb_sg.id]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }
}

# 4. EC2 Instances for video processing/streaming
resource "aws_instance" "streaming_server" {
  count                  = 2
  ami                    = "ami-0c55b159cbfafe1f0" # Amazon Linux 2 AMI
  instance_type          = "t3.medium"
  subnet_id              = element(module.vpc.private_subnets, count.index)
  vpc_security_group_ids = [aws_security_group.ec2_sg.id]

  user_data = <<-EOF
              #!/bin/bash
              yum update -y
              yum install -y httpd
              systemctl start httpd
              systemctl enable httpd
              echo "<h1>Video Streaming Server ${count.index}</h1>" > /var/www/html/index.html
              EOF

  tags = {
    Name = "streaming-node-${count.index}"
  }
}

# 5. Application Load Balancer
resource "aws_lb" "streaming_alb" {
  name               = "streaming-site-lb"
  internal           = false
  load_balancer_type = "application"
  security_groups    = [aws_security_group.alb_sg.id]
  subnets            = module.vpc.public_subnets

  enable_deletion_protection = false
}

# 6. ALB Target Group
resource "aws_lb_target_group" "streaming_tg" {
  name     = "streaming-target-group"
  port     = 80
  protocol = "HTTP"
  vpc_id   = module.vpc.vpc_id

  health_check {
    path                = "/"
    interval            = 30
    timeout             = 5
    healthy_threshold   = 2
    unhealthy_threshold = 2
  }
}

# 7. ALB Listener
resource "aws_lb_listener" "front_end" {
  load_balancer_arn = aws_lb.streaming_alb.arn
  port              = "80"
  protocol          = "HTTP"

  default_action {
    type             = "forward"
    target_group_arn = aws_lb_target_group.streaming_tg.arn
  }
}

# 8. Target Group Attachment
resource "aws_lb_target_group_attachment" "streaming_attach" {
  count            = 2
  target_group_arn = aws_lb_target_group.streaming_tg.arn
  target_id        = aws_instance.streaming_server[count.index].id
  port             = 80
}

# 9. Route53 DNS Configuration
resource "aws_route53_zone" "streaming_zone" {
  name = "streaming-example-site.com"
}

resource "aws_route53_record" "www" {
  zone_id = aws_route53_zone.streaming_zone.zone_id
  name    = "www.streaming-example-site.com"
  type    = "A"

  alias {
    name                   = aws_lb.streaming_alb.dns_name
    zone_id                = aws_lb.streaming_alb.zone_id
    evaluate_target_health = true
  }
}
