provider "aws" {
  region = "us-east-1"
}

# KMS Key for RDS encryption
resource "aws_kms_key" "db_encryption_key" {
  description             = "KMS key for RDS PostgreSQL encryption"
  deletion_window_in_days = 10
  enable_key_rotation     = true
}

# Custom Parameter Group for PostgreSQL
resource "aws_db_parameter_group" "postgres_custom" {
  name   = "postgres15-custom-params"
  family = "postgres15"

  parameter {
    name  = "log_connections"
    value = "1"
  }

  parameter {
    name  = "client_encoding"
    value = "utf8"
  }
}

# DB Subnet Group (Assumes existing subnets in a VPC)
resource "aws_db_subnet_group" "db_subnets" {
  name       = "main-db-subnet-group"
  subnet_ids = ["subnet-12345678", "subnet-87654321"] # Replace with actual subnet IDs

  tags = {
    Name = "My DB Subnet Group"
  }
}

# Security Group for Database Access
resource "aws_security_group" "db_sg" {
  name        = "rds-postgres-sg"
  description = "Allow inbound traffic to PostgreSQL"
  vpc_id      = "vpc-12345678" # Replace with actual VPC ID

  ingress {
    from_port   = 5432
    to_port     = 5432
    protocol    = "tcp"
    cidr_blocks = ["10.0.0.0/16"] # Restricted to internal VPC range
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }
}

# Random password for initial setup
resource "random_password" "db_password" {
  length           = 16
  special          = true
  override_special = "!#$%&*()-_=+[]{}<>:?"
}

# RDS PostgreSQL Instance
resource "aws_db_instance" "secure_postgres" {
  identifier           = "secure-postgresql-instance"
  allocated_storage    = 20
  storage_type         = "gp3"
  engine               = "postgres"
  engine_version       = "15.4"
  instance_class       = "db.t3.medium"
  db_name              = "application_db"
  username             = "db_admin"
  password             = random_password.db_password.result

  # Security and Encryption
  storage_encrypted    = true
  kms_key_id          = aws_kms_key.db_encryption_key.arn

  # Network and Connectivity
  db_subnet_group_name   = aws_db_subnet_group.db_subnets.name
  vpc_security_group_ids = [aws_security_group.db_sg.id]
  publicly_accessible    = false

  # High Availability and Maintenance
  multi_az               = true
  parameter_group_name   = aws_db_parameter_group.postgres_custom.name
  skip_final_snapshot    = true
  backup_retention_period = 7
  deletion_protection     = false # Set to true for production

  tags = {
    Environment = "production"
    ManagedBy   = "Terraform"
  }
}

