resource "random_id" "bucket_suffix" {
  byte_length = 4
}

# S3 Bucket for Long-Term Data Storage
resource "aws_s3_bucket" "long_term_storage" {
  bucket = "long-term-archive-storage-${random_id.bucket_suffix.hex}"

  tags = {
    Name        = "Long Term Data Storage"
    Environment = "Production"
  }
}

# Lifecycle Configuration to transition data to Glacier and Deep Archive
resource "aws_s3_bucket_lifecycle_configuration" "archive_lifecycle" {
  bucket = aws_s3_bucket.long_term_storage.id

  rule {
    id     = "archive-to-glacier-and-deep-archive"
    status = "Enabled"

    # Transition to Glacier after 30 days
    transition {
      days          = 30
      storage_class = "GLACIER"
    }

    # Transition to Deep Archive after 180 days (cheapest storage)
    transition {
      days          = 180
      storage_class = "DEEP_ARCHIVE"
    }

    # Optional: Clean up old versions if versioning is enabled
    noncurrent_version_expiration {
      noncurrent_days = 365
    }
  }
}

# AWS Backup Vault to store backups
resource "aws_backup_vault" "main_vault" {
  name        = "long-term-backup-vault-${random_id.bucket_suffix.hex}"
  kms_key_arn = null # Uses default AWS Backup KMS key
}

# AWS Backup Plan for automated long-term retention
resource "aws_backup_plan" "long_term_plan" {
  name = "daily-backup-long-term-retention"

  rule {
    rule_name         = "daily_backup_rule"
    target_vault_name = aws_backup_vault.main_vault.name
    schedule          = "cron(0 5 * * ? *)" # Daily at 05:00 AM

    lifecycle {
      cold_storage_after = 30   # Move to cold storage after 30 days
      delete_after       = 2555 # Retain for 7 years (2555 days)
    }
  }
}

# IAM Role for AWS Backup to perform tasks
resource "aws_iam_role" "backup_role" {
  name               = "aws-backup-service-role-${random_id.bucket_suffix.hex}"
  assume_role_policy = <<POLICY
{
  "Version": "2012-10-17",
  "Statement": [
    {
      "Action": "sts:AssumeRole",
      "Principal": {
        "Service": "backup.amazonaws.com"
      },
      "Effect": "Allow",
      "Sid": ""
    }
  ]
}
POLICY
}

resource "aws_iam_role_policy_attachment" "backup_policy" {
  policy_arn = "arn:aws:iam::aws:policy/service-role/AWSBackupServiceRolePolicyForBackup"
  role       = aws_iam_role.backup_role.name
}

# Selection of resources to back up (Example: tagging resources for backup)
resource "aws_backup_selection" "example" {
  iam_role_arn = aws_iam_role.backup_role.arn
  name         = "long-term-backup-selection"
  plan_id      = aws_backup_plan.long_term_plan.id

  selection_tag {
    type  = "STRINGEQUALS"
    key   = "Backup"
    value = "LongTerm"
  }
}

