}

# Create an AWS S3 Glacier Vault
resource "aws_glacier_vault" "archive" {
  name = "corporate-archive-vault-${random_id.suffix.hex}"

  notification {
    sns_topic = aws_sns_topic.glacier_notifications.arn
    events    = ["ArchiveRetrievalCompleted", "InventoryRetrievalCompleted"]
  }
}

resource "aws_sns_topic" "glacier_notifications" {
  name = "glacier-notifications-${random_id.suffix.hex}"
}

# IAM Role for AWS Data Lifecycle Manager (DLM)
resource "aws_iam_role" "dlm_lifecycle_role" {
  name = "dlm-lifecycle-role-${random_id.suffix.hex}"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "dlm.amazonaws.com"
        }
      }
    ]
  })
}

resource "aws_iam_role_policy" "dlm_lifecycle" {
  name = "dlm-lifecycle-policy"
  role = aws_iam_role.dlm_lifecycle_role.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "ec2:CreateSnapshot",
          "ec2:CreateSnapshots",
          "ec2:DeleteSnapshot",
          "ec2:DescribeInstances",
          "ec2:DescribeVolumes",
          "ec2:DescribeSnapshots",
          "ec2:ModifySnapshotTier" # Required to move snapshots to Glacier/Archive tier
        ]
        Resource = "*"
      },
      {
        Effect = "Allow"
        Action = [
          "ec2:CreateTags"
        ]
        Resource = "arn:aws:ec2:*::snapshot/*"
      }
    ]
  })
}

# AWS Data Lifecycle Manager Policy
# This policy manages EBS snapshots and moves them to the Archive tier (Glacier)
resource "aws_dlm_lifecycle_policy" "example" {
  description        = "Daily EBS snapshots with Glacier archiving"
  execution_role_arn = aws_iam_role.dlm_lifecycle_role.arn
  state              = "ENABLED"

  policy_details {
    resource_types = ["VOLUME"]

    target_tags = {
      Snapshot = "true"
    }

    schedule {
      name = "DailyBackup"

      create_rule {
        interval      = 24
        interval_unit = "HOURS"
        times         = ["03:00"]
      }

      retain_rule {
        count = 7
      }

      # Archiving snapshots to the Glacier tier
      archive_rule {
        retain_rule {
          count = 1 // Retain 1 snapshot in archive tier
        }
      }
    }
  }
}

